// Webhook body carries { application_id, thesis_id? } (design.md SS5's own trigger
// shape). thesis_id is accepted but NOT currently consumed anywhere downstream --
// design SS3.5: api_applications already resolves the live thesis evaluation (the
// stale-thesis trap), "use it -- do not re-derive from scores"; no override mechanism
// is specified anywhere in SS3-SS9. Accepted here only so a future caller-supplied
// override has somewhere to land without a webhook-contract change.
const { randomUUID } = require('crypto');
const item = $input.first().json;
const body = item.body || {};
const application_id = body.application_id || item.application_id || null;
const thesis_id = body.thesis_id || item.thesis_id || null;
return [{ json: { application_id, thesis_id, run_id: randomUUID() } }];

const SB = String($env.SUPABASE_URL || '').replace(/\/rest\/v1\/?$/, '');
const KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const self = this;
async function pg(method, path, body, prefer) {
  const headers = { apikey: KEY, Authorization: 'Bearer ' + KEY, 'Content-Type': 'application/json' };
  if (prefer) headers.Prefer = prefer;
  return await self.helpers.httpRequest({ method, url: SB + '/rest/v1/' + path, headers, body, json: true });
}

